void levelOrder(struct Node *root) {
    if(root == NULL) return;

    struct Node* queue[100];
    int front = 0, rear = 0;
    queue[rear++] = root;

    while(front < rear) {
        struct Node *node = queue[front++];
        printf("%d ", node->data);

        if(node->left) queue[rear++] = node->left;
        if(node->right) queue[rear++] = node->right;
    }
}

